// App.js
import React from 'react';
import ClickableIcon from './ClickableIcon';

const App = () => {
  const handleIconClick = () => {
    alert('Icon clicked!');
  };

  return (
    <div>
      <h1>Clickable Icon Example</h1>
      <ClickableIcon onClick={handleIconClick} />
    </div>
  );
};

export default App;
